import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";

const AdminDashboard = () => {
  const navigate = useNavigate();

  useEffect(() => {
    const role = localStorage.getItem("userRole");
    if (role !== "ADMIN") {
      navigate("/login");
    }
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem("userId");
    localStorage.removeItem("userRole");
    navigate("/admin-login");
  };

  return (
    <div className="min-h-screen bg-gray-100 p-8">
      <div className="max-w-4xl mx-auto">
        <div className="flex justify-between items-center bg-white p-6 rounded-2xl shadow-md mb-8 border-l-4 border-purple-500">
          <h1 className="text-3xl font-bold text-gray-800">Admin Dashboard</h1>
          <button 
            onClick={handleLogout}
            className="bg-red-500 hover:bg-red-600 text-white px-5 py-2 rounded-lg font-medium transition duration-200"
          >
            Logout
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-white p-6 rounded-xl shadow border border-gray-100 hover:shadow-lg transition duration-300">
            <h2 className="text-xl font-bold text-gray-700 mb-2">Manage Users</h2>
            <p className="text-gray-500 mb-4">View, edit, and delete user accounts across the platform.</p>
            <button className="text-purple-600 font-semibold hover:text-purple-800">Go to Users &rarr;</button>
          </div>

          <div className="bg-white p-6 rounded-xl shadow border border-gray-100 hover:shadow-lg transition duration-300">
            <h2 className="text-xl font-bold text-gray-700 mb-2">Manage Bookings</h2>
            <p className="text-gray-500 mb-4">Review and manage all campus reservations and room bookings.</p>
            <button className="text-purple-600 font-semibold hover:text-purple-800">Go to Bookings &rarr;</button>
          </div>

          <div className="bg-white p-6 rounded-xl shadow border border-gray-100 hover:shadow-lg transition duration-300">
            <h2 className="text-xl font-bold text-gray-700 mb-2">Manage Tickets</h2>
            <p className="text-gray-500 mb-4">Handle support tickets and resolve user issues promptly.</p>
            <button className="text-purple-600 font-semibold hover:text-purple-800">Go to Tickets &rarr;</button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
